<form class="form-card" method="post" action="<?= $e($action) ?>"><input type="hidden" name="_csrf_token" value="<?= $e($csrfToken) ?>"><div class="form-grid"><?php foreach(['code'=>'Mã','name'=>'Tên','discount_value'=>'Giá trị giảm','max_discount'=>'Giảm tối đa','minimum_order_value'=>'Đơn tối thiểu','usage_limit'=>'Giới hạn tổng','per_user_limit'=>'Giới hạn mỗi khách'] as $key=>$label):?><label class="form-field"><span><?= $e($label) ?><?= in_array($key,['code','name','discount_value','minimum_order_value'],true)?' *':'' ?></span><input name="<?= $e($key) ?>" value="<?= $e($values[$key]) ?>" <?= in_array($key,['code','name','discount_value','minimum_order_value'],true)?'required':'' ?>></label><?php endforeach;?><label class="form-field"><span>Loại giảm *</span><select name="discount_type"><option value="fixed" <?= $values['discount_type']==='fixed'?'selected':'' ?>>Cố định</option><option value="percentage" <?= $values['discount_type']==='percentage'?'selected':'' ?>>Phần trăm</option></select></label><label class="form-field"><span>Bắt đầu *</span><input type="datetime-local" name="start_at" required value="<?= $e($values['start_at']) ?>"></label><label class="form-field"><span>Kết thúc *</span><input type="datetime-local" name="end_at" required value="<?= $e($values['end_at']) ?>"></label></div><label class="form-field"><span>Mô tả</span><textarea name="description" maxlength="2000"><?= $e($values['description']) ?></textarea></label><?php foreach(['tier_ids'=>'Hạng mục tiêu','service_ids'=>'Dịch vụ mục tiêu','vehicle_type_ids'=>'Loại xe mục tiêu'] as $key=>$legend):?><fieldset class="form-field"><legend><?= $e($legend) ?></legend><div class="form-grid"><?php $optionKey=$key==='tier_ids'?'tiers':($key==='service_ids'?'services':'vehicle_types'); foreach($options[$optionKey] as $option): $label=$option['name']??$option['display_name'];?><label><input type="checkbox" name="<?= $e($key) ?>[]" value="<?= $e($option['id']) ?>" <?= in_array((int)$option['id'],array_map('intval',$values[$key]),true)?'checked':'' ?>> <?= $e($label) ?></label><?php endforeach;?></div></fieldset><?php endforeach;?><div class="form-actions"><button class="button button-primary">Lưu promotion</button><a class="button button-outline" href="/admin/promotion">Hủy</a></div></form>
